import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjAccordion } from "./OjAccordion";
export { OjAccordion };

/**
 * Create an instance of [[OjAccordion]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojAccordion(driver, By.id('my-oj-accordion'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojAccordion(driver: DriverLike, by: By): Promise<OjAccordion> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjAccordion
  if (!(webEl instanceof OjAccordion)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-accordion>`);
  }
  return webEl;
}

register("oj-accordion", OjAccordion);
